#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline void print(const int &x){if(x>9)print(x/10);putchar(x%10+'0');}
inline void rd(bool &x){char c;do c=getchar();while(c!='0'&&c!='1');x=c=='1';}
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2010;bool a[N][N];int n,fa[N];
inline void ins(int x,int y){print(x);putchar(' ');print(y);putchar('\n');} 
inline void Solve()
{
	n=read();rep(1,n,i)fa[i]=i;
	rep(1,n,i)rep(i,n,j)rd(a[i][j]);
	rep(1,n,r)drep(r-1,1,l)if(fa[r]>l&&a[l][r])
	{
		ins(l,r);int x=fa[fa[r]-1];
		if(x>l)ins(l,fa[r]-1),x=fa[x-1];		
		while(x>l)ins(x,r),x=fa[x-1];
		rep(l,r,i)fa[i]=fa[l];
	}
}
int main()
{
	int T=read();while(T--)Solve();
}
